<script>
(function(){
function g(id){return document.getElementById(id)}
function e(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;')}
function br(s){return e(s).replace(/\n/g,'<br>')}
function col(name){var pal=['#5e72e4','#c49ab8','#34c759','#ff6b9d','#f5a623','#30d158','#0a84ff','#af52de','#ff9f0a','#64d2ff'];var h=0,s=String(name||'');for(var i=0;i<s.length;i++)h=(h*31+s.charCodeAt(i))>>>0;return pal[h%pal.length]}

function parseSent(raw){
  raw=String(raw||'').replace(/\r/g,'').trim();
  var all=raw.split('\n');
  var isSep=function(l){return /^[─━\-—_]{5,}$/.test(l.trim())};
  var date='',time='';
  for(var i=all.length-1;i>=0;i--){
    var m=all[i].trim().match(/^(?:(.*?)\s{2,})?(\d{1,2}:\d{2})$/);
    if(m){date=(m[1]||'').trim();time=m[2];all.splice(i,1);break}
  }
  var header=(all[0]||'').trim(),type='',title='',hm;
  if((hm=header.match(/^\[\s*Chat:\s*(.*?)\s*\]$/i))){type='chat';title=hm[1]}
  else if(/^\[\s*Social Actions\s*\]$/i.test(header)){type='social';title='Social'}
  else if(/^\[\s*Order Placed\s*\]$/i.test(header)){type='shop';title='Order Placed'}
  else if(/^\[\s*Bank Transfer\s*\]$/i.test(header)){type='bank';title='Bank Transfer'}
  else if((hm=header.match(/^\[\s*Contact Added:\s*(.*?)\s*\]$/i))){type='contact';title=hm[1]}
  else{type='unknown';title=header}
  var items=[],extra=[];
  for(var j=1;j<all.length;j++){
    var line=all[j];if(isSep(line)||!line.trim())continue;
    var nm=line.match(/^(\d+)\.\s+([\s\S]*)$/);
    if(nm){items.push(nm[2].trim())}
    else if(/^Total/i.test(line.trim())){extra.push(line.trim())}
    else if(items.length){items[items.length-1]+='\n'+line.trim()}
  }
  return {type:type,title:title,date:date,time:time,items:items,extra:extra,header:header};
}

function nav(title){
  return '<div class="nav"><button class="nav-bk">‹</button><div class="nav-ti">'+title+'</div><div style="min-width:44px"></div></div>';
}

function scChat(P){
  var group=/\(Group\)/i.test(P.title),name=P.title.replace(/\s*\(Group\)\s*$/i,''),c=col(name);
  var head='<div class="nav"><button class="nav-bk">‹</button>'
    +'<div class="nav-ti" style="display:flex;align-items:center;gap:6px;justify-content:center">'
    +'<div style="width:24px;height:24px;border-radius:50%;background:'+c+';flex-shrink:0"></div>'+e(name)+(group?' 👥':'')+'</div>'
    +'<div style="min-width:44px"></div></div>';
  var b='<div class="tbdy">';
  if(!P.items.length)b+='<div class="empty" style="padding:24px 0">No messages</div>';
  P.items.forEach(function(t){b+='<div class="bbl ou">'+br(t)+(P.time?'<div class="bts">'+e(P.time)+'</div>':'')+'</div>'});
  b+='</div>';
  return head+'<div class="ab">'+b+'</div>';
}

function scSocial(P){
  var un='You',b='';
  P.items.forEach(function(t){
    var mm=t.match(/^\[([^\]]+)\]\s*([\s\S]*)$/);
    var tag=mm?mm[1].trim():'',rest=mm?mm[2].trim():t,head=(tag.split(/\s+/)[0]||'').toUpperCase();
    if(head==='NEW'){
      b+='<div class="post"><div class="post-head"><div class="post-av" style="background:#0a84ff">'+e(un.charAt(0))+'</div>'
        +'<div class="post-info"><div class="post-nm">'+e(un)+'</div><div class="post-ts">'+e(P.time||'now')+'</div></div></div>'
        +'<div class="post-txt">'+br(rest)+'</div></div>';
      return;
    }
    var ic='📌',lbl=tag,cc='#5e72e4';
    if(head==='LIKE'&&/COMMENT/i.test(tag)){ic='❤️';lbl='Liked a comment';cc='#ff3b5c'}
    else if(head==='LIKE'){ic='❤️';lbl='Liked a post';cc='#ff3b5c'}
    else if(head==='COMMENT'){ic='💬';lbl='Commented';cc='#0a84ff'}
    else if(head==='REPLY'){ic='↩️';var rt=tag.match(/REPLY to (.*?) on/i);lbl='Replied'+(rt?' to '+rt[1]:'');cc='#30d158'}
    else if(head==='SHARE'){ic='🔁';lbl='Shared a post';cc='#af52de'}
    var q=tag.match(/[—-]\s*"([\s\S]*?)"/);var sub=rest||(q?'“'+q[1]+'”':'');
    b+='<div class="cr"><div class="cav" style="background:'+cc+'">'+ic+'</div>'
      +'<div class="ci2"><div class="ch2"><div class="cn2">'+e(lbl)+'</div><div class="ct2">'+e(P.time||'')+'</div></div>'
      +'<div class="cp2">'+e(sub)+'</div></div></div>';
  });
  return nav('Social')+'<div class="ab">'+b+'</div>';
}

function scShop(P){
  var b='';
  P.items.forEach(function(t){
    var mm=t.match(/^([\s\S]*?)\s*[×x]\s*(\d+)\s*@\s*([\s\S]*)$/);
    var nm=mm?mm[1].trim():t,qty=mm?mm[2]:'',pr=mm?mm[3].trim():'';
    b+='<div class="cart-item"><div class="cart-ic">🛍️</div>'
      +'<div class="cart-info"><div class="cart-nm">'+e(nm)+'</div>'+(qty?'<div class="cart-sub">× '+e(qty)+'</div>':'')+'</div>'
      +(pr?'<div class="cart-pr">'+e(pr)+'</div>':'')+'</div>';
  });
  var tot='';P.extra.forEach(function(x){var mm=x.match(/^Total[^:]*:\s*(.*)$/i);tot+='<div class="cart-total"><div class="cart-total-l">Total</div><div class="cart-total-r">'+e(mm?mm[1]:x)+'</div></div>'});
  return nav('Order Placed')+'<div class="ab">'+b+tot+'</div>';
}

function scBank(P){
  var b='';
  P.items.forEach(function(t){
    var mm=t.match(/^To:\s*([\s\S]*?)\s{2,}Amount:\s*([\s\S]*?)(?:\s*\(([\s\S]*)\))?$/);
    var to=mm?mm[1].trim():t,amt=mm?mm[2].trim():'',note=mm&&mm[3]?mm[3].trim():'';
    b+='<div class="tx"><div class="tx-ic db">↗</div>'
