  var tot='';P.extra.forEach(function(x){var mm=x.match(/:\s*(.*)$/);tot+='<div class="cart-total"><div class="cart-total-l">Total sent</div><div class="cart-total-r" style="color:#ff453a">'+e(mm?mm[1]:x)+'</div></div>'});
  return nav('Transfer Sent')+'<div class="ab">'+b+tot+'</div>';
}

function scContact(P){
  var c=col(P.title);
  var b='<div class="cr"><div class="cav" style="background:'+c+'">'+e((P.title||'?').charAt(0))+'</div>'
    +'<div class="ci2"><div class="ch2"><div class="cn2">'+e(P.title)+'</div><div class="ct2">'+e(P.time||'')+'</div></div>'
    +'<div class="cp2">Added to contacts</div></div></div>';
  return nav('Contacts')+'<div class="ab">'+b+'</div>';
}

function render(){
  var view=g('view');if(!view)return;
  var raw='';try{var el=g('upd');if(el)raw=(el.textContent||'')}catch(_){}
  var P=parseSent(raw);
  var sbt=g('sbt');if(sbt)sbt.textContent=P.time||'';
  var inner;
  if(P.type==='chat')inner=scChat(P);
  else if(P.type==='social')inner=scSocial(P);
  else if(P.type==='shop')inner=scShop(P);
  else if(P.type==='bank')inner=scBank(P);
  else if(P.type==='contact')inner=scContact(P);
  else inner=nav('Phone')+'<div class="ab"><div class="empty">'+br(raw)+'</div></div>';
  view.innerHTML='<div class="scr app">'+inner+'</div>';
}
if(typeof document!=='undefined'){
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',render);else render();
}
if(typeof module!=='undefined')module.exports={parseSent:parseSent,render:render};
})();

</script>
